// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/metrics", wrapper.GetJSONMetrics)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/notifications", wrapper.ListNotifications)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/notifications", wrapper.CreateNotification)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/notifications/batch", wrapper.CreateBatch)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/notifications/batch/{id}", wrapper.GetBatch)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/notifications/{id}", wrapper.GetNotification)
	})
	r.Group(func(r chi.Router) {
		r.Patch(options.BaseURL+"/api/v1/notifications/{id}/cancel", wrapper.CancelNotification)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/notifications/{id}/trace", wrapper.GetNotificationTrace)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/templates", wrapper.ListTemplates)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/api/v1/templates", wrapper.CreateTemplate)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/api/v1/templates/{id}", wrapper.DeleteTemplate)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/api/v1/templates/{id}", wrapper.GetTemplate)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/api/v1/templates/{id}", wrapper.ReplaceTemplate)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/healthz/live", wrapper.GetHealthzLive)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/healthz/ready", wrapper.GetHealthzReady)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/metrics", wrapper.GetPrometheusMetrics)
	})

	return r
}

